from flask import Flask, Blueprint, g, request
import uuid

app = Flask(__name__)
api = Blueprint('api', __name__, url_prefix='/api')

@app.before_request
def inject_request_id():
    g.request_id = request.headers.get('X-Request-ID', str(uuid.uuid4()))

@api.before_request
def require_auth():
    if not request.headers.get('Authorization'):
        return {'error': 'Unauthorized'}, 401

@app.after_request
def attach_request_id(response):
    response.headers['X-Request-ID'] = g.get('request_id', '')
    return response

app.register_blueprint(api)

from flask import Flask, Blueprint, url_for

users_bp = Blueprint('users', __name__, url_prefix='/api/v1/users')

@users_bp.route('/', methods=['GET'])
def list_users():
    return {'users': []}

@users_bp.route('/<int:user_id>', methods=['GET', 'PUT'])
def user_detail(user_id: int):
    # user_id is already an int; Flask 404s if it's not
    return {'id': user_id}

@users_bp.route('/<int:user_id>/posts/<path:slug>')
def user_post(user_id: int, slug: str):
    return url_for('users.user_post', user_id=user_id, slug=slug)

app = Flask(__name__)
app.register_blueprint(users_bp)

from flask import Flask, request, jsonify
from marshmallow import Schema, fields, ValidationError, RAISE

app = Flask(__name__)

class CreatePostSchema(Schema):
    class Meta:
        unknown = RAISE
    title = fields.Str(required=True, validate=lambda v: 1 <= len(v) <= 120)
    body = fields.Str(required=True, load_default=None)

schema = CreatePostSchema()

@app.errorhandler(ValidationError)
def handle_validation_error(err):
    return jsonify({"errors": err.messages}), 422

@app.post("/posts")
def create_post():
    data = schema.load(request.get_json(force=True))
    # data is clean — safe to pass to DB layer
    return jsonify(data), 201

import jwt
from functools import wraps
from flask import request, g, jsonify, current_app

def require_auth(role=None):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            token = request.headers.get('Authorization', '').removeprefix('Bearer ')
            if not token:
                return jsonify(error='Missing token'), 401
            try:
                payload = jwt.decode(token, current_app.config['JWT_SECRET'], algorithms=['HS256'])
            except jwt.ExpiredSignatureError:
                return jsonify(error='Token expired'), 401
            except jwt.InvalidTokenError:
                return jsonify(error='Invalid token'), 401
            if role and payload.get('role') != role:
                return jsonify(error='Forbidden'), 403
            g.user = payload
            return f(*args, **kwargs)
        return wrapper
    return decorator

from flask import Flask, jsonify
from werkzeug.exceptions import HTTPException

app = Flask(__name__)

def make_error(status: int, code: str, message: str):
    return jsonify({"status": status, "code": code, "message": message}), status

@app.errorhandler(HTTPException)
def handle_http(e: HTTPException):
    return make_error(e.code, e.name.upper().replace(" ", "_"), e.description)

@app.errorhandler(Exception)
def handle_generic(e: Exception):
    if isinstance(e, HTTPException):
        return handle_http(e)
    app.logger.exception(e)
    return make_error(500, "INTERNAL_ERROR", "An unexpected error occurred")

