from dataclasses import dataclass, asdict
from flask import Flask, request, jsonify
import re

app = Flask(__name__)
app.json.sort_keys = False

def to_camel(d: dict) -> dict:
    def camel(s): return re.sub(r'_([a-z])', lambda m: m.group(1).upper(), s)
    return {camel(k): v for k, v in d.items() if v is not None}

@dataclass
class UserDTO:
    user_id: int
    display_name: str
    avatar_url: str | None = None

@app.post('/users')
def create_user():
    body = request.get_json(force=True)
    if not body or 'display_name' not in body:
        return jsonify(error='display_name required'), 400
    dto = UserDTO(user_id=1, display_name=body['display_name'])
    return jsonify(to_camel(asdict(dto))), 201

